import React, { useState } from "react";
import { useParams } from "react-router-dom";
import {
  Container,
  Typography,
  Grid,
  Paper,
  Avatar,
  Divider,
  List,
  ListItem,
  ListItemText,
  Button,
  Box,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
} from "@mui/material";

import { doctors } from "../data/doctors";

const DoctorProfile = () => {
  const { doctorId } = useParams();
  const doctor = doctors.find((d) => d.id === Number(doctorId));

  const [openBooking, setOpenBooking] = useState(false);
  const [formData, setFormData] = useState({
    fullName: "",
    age: "",
    contactNumber: "",
    email: "",
    preferredTime: "",
  });
  const [errors, setErrors] = useState({});

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: "" }));
  };

  const handleConfirmBooking = () => {
    const newErrors = {};
    let hasError = false;

    if (!formData.fullName.trim()) {
      newErrors.fullName = "Required";
      hasError = true;
    }
    if (!formData.age.trim()) {
      newErrors.age = "Required";
      hasError = true;
    }
    if (!formData.contactNumber.trim()) {
      newErrors.contactNumber = "Required";
      hasError = true;
    }
    if (!formData.email.trim()) {
      newErrors.email = "Required";
      hasError = true;
    }
    if (!formData.preferredTime) {
      newErrors.preferredTime = "Required";
      hasError = true;
    }

    setErrors(newErrors);
    if (hasError) {
      alert("Please fill all required fields!");
      return;
    }

    // Save booking
    const newAppointment = {
      id: Date.now(),
      doctorName: doctor.name,
      hospitalName: "City Care Hospital", // Change this later if you add hospital name to doctor data
      patientName: formData.fullName,
      age: formData.age,
      contactNumber: formData.contactNumber,
      email: formData.email,
      preferredTime: formData.preferredTime,
      status: "Scheduled",
      date: new Date().toLocaleDateString(),
    };

    const existing = JSON.parse(localStorage.getItem("appointments")) || [];
    localStorage.setItem(
      "appointments",
      JSON.stringify([...existing, newAppointment]),
    );

    alert(
      `Booking Confirmed!\n\nDoctor: ${doctor.name}\nPatient: ${formData.fullName}\nTime: ${formData.preferredTime}`,
    );

    setOpenBooking(false);
    setFormData({
      fullName: "",
      age: "",
      contactNumber: "",
      email: "",
      preferredTime: "",
    });
    setErrors({});
  };

  if (!doctor) return <Typography>Doctor not found</Typography>;

  return (
    <Container maxWidth="xl" sx={{ py: 10 }}>
      <Paper
        elevation={6}
        sx={{
          p: { xs: 5, md: 10 },
          borderRadius: 4,
          maxWidth: 1400,
          mx: "auto",
        }}
      >
        <Grid container spacing={8}>
          <Grid item xs={12} md={5}>
            <Box sx={{ textAlign: "center" }}>
              <Avatar
                src={doctor.image}
                sx={{ width: 420, height: 420, mx: "auto", mb: 5 }}
              />
              <Typography variant="h3" fontWeight="bold">
                {doctor.name}
              </Typography>
              <Typography variant="h5" color="primary">
                {doctor.specialty}
              </Typography>
            </Box>
          </Grid>

          <Grid item xs={12} md={7}>
            <Typography
              variant="h4"
              gutterBottom
              sx={{ mb: 5, fontWeight: 600, color: "#1976d2" }}
            >
              Professional Details
            </Typography>

            <Divider sx={{ mb: 5 }} />

            <List disablePadding>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Experience</Typography>}
                  secondary={doctor.experience}
                />
              </ListItem>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Qualification</Typography>}
                  secondary={doctor.qualification}
                />
              </ListItem>
              <ListItem sx={{ py: 3 }}>
                <ListItemText
                  primary={<Typography variant="h6">Availability</Typography>}
                  secondary={doctor.availability}
                />
              </ListItem>
              <ListItem sx={{ py: 3, alignItems: "flex-start" }}>
                <ListItemText
                  primary={<Typography variant="h6">About</Typography>}
                  secondary={
                    <Typography sx={{ fontSize: "1.1rem", lineHeight: 1.8 }}>
                      {doctor.bio}
                    </Typography>
                  }
                />
              </ListItem>
            </List>

            <Box sx={{ mt: 10, textAlign: "center" }}>
              <Button
                variant="contained"
                color="primary"
                size="large"
                sx={{ py: 3, px: 10, fontSize: "1.4rem" }}
                onClick={() => setOpenBooking(true)}
              >
                Book Appointment
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Paper>

      {/* Booking Dialog */}
      <Dialog
        open={openBooking}
        onClose={() => setOpenBooking(false)}
        maxWidth="sm"
        fullWidth
      >
        <DialogTitle>Book Appointment with {doctor.name}</DialogTitle>
        <DialogContent>
          <Grid container spacing={3} sx={{ mt: 1 }}>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Full Name"
                name="fullName"
                value={formData.fullName}
                onChange={handleInputChange}
                error={!!errors.fullName}
                helperText={errors.fullName}
              />
            </Grid>
            <Grid item xs={6}>
              <TextField
                fullWidth
                label="Age"
                name="age"
                type="number"
                value={formData.age}
                onChange={handleInputChange}
                error={!!errors.age}
                helperText={errors.age}
              />
            </Grid>
            <Grid item xs={6}>
              <TextField
                fullWidth
                label="Contact Number"
                name="contactNumber"
                value={formData.contactNumber}
                onChange={handleInputChange}
                error={!!errors.contactNumber}
                helperText={errors.contactNumber}
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Email"
                name="email"
                type="email"
                value={formData.email}
                onChange={handleInputChange}
                error={!!errors.email}
                helperText={errors.email}
              />
            </Grid>
            <Grid item xs={12}>
              <FormControl fullWidth error={!!errors.preferredTime}>
                <InputLabel>Preferred Time</InputLabel>
                <Select
                  name="preferredTime"
                  value={formData.preferredTime}
                  label="Preferred Time"
                  onChange={handleInputChange}
                >
                  <MenuItem value="09:00 AM">09:00 AM</MenuItem>
                  <MenuItem value="10:00 AM">10:00 AM</MenuItem>
                  <MenuItem value="11:00 AM">11:00 AM</MenuItem>
                  <MenuItem value="02:00 PM">02:00 PM</MenuItem>
                  <MenuItem value="03:00 PM">03:00 PM</MenuItem>
                  <MenuItem value="04:00 PM">04:00 PM</MenuItem>
                  <MenuItem value="05:00 PM">05:00 PM</MenuItem>
                </Select>
              </FormControl>
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpenBooking(false)}>Cancel</Button>
          <Button variant="contained" onClick={handleConfirmBooking}>
            Confirm Booking
          </Button>
        </DialogActions>
      </Dialog>
    </Container>
  );
};

export default DoctorProfile;
